        $g = @glob($d.'*fpm*.sock'); if ($g) $socks = array_merge($socks, $g);
    }
    foreach (["/var/run/php/php{$ver}-fpm.sock","/run/php/php{$ver}-fpm.sock","/var/run/php-fpm.sock"] as $f) {
        if (@file_exists($f)) $socks[] = $f;
    }
    // Scan /proc/net/unix for FPM sockets
    $pnu = @file_get_contents('/proc/net/unix');
