            $t=@disk_total_space($cwd);$f=@disk_free_space($cwd);if($t===false)return"df: error";
            $u=$t-$f;$fm=function($b){if($b>=1073741824)return round($b/1073741824,1).'G';if($b>=1048576)return round($b/1048576,1).'M';return round($b/1024,1).'K';};
            return sprintf("Filesystem  Size  Used  Avail Use%%\n%-10s %5s %5s %5s  %d%%",$cwd,$fm($t),$fm($u),$fm($f),round($u/$t*100));
