            $o=sprintf("%-7s %-6s %s\n","PID","UID","COMMAND");$ds=@glob('/proc/[0-9]*');
            if($ds)foreach(array_slice($ds,0,40)as$d){$cl=@file_get_contents($d.'/cmdline');if($cl===false)continue;
                $st=@file_get_contents($d.'/status');$uid='';if($st&&preg_match('/^Uid:\s+(\d+)/m',$st,$m))$uid=$m[1];
