                @mkdir($dst, 0755, true);
                foreach ($ri as $o) {
                    $target = $dst . '/' . $ri->getSubPathname();
                    $o->isDir() ? @mkdir($target, 0755) : @copy($o->getPathname(), $target);
                }
                $r = "COPIED";
            } else {
                $r = @copy($src, $dst) ? "COPIED" : "ERR: " . (!is_writable($req['dst']) ? "Dest not writable" : "Copy failed");
            }
            break;
        case 'move':
            if (!file_exists($req['fp'])) { $r = "ERR: Source not found"; break; }
            $r = @rename($req['fp'], $req['dst'] . '/' . basename($req['fp'])) ? "MOVED" : "ERR: " . (!is_writable($req['dst']) ? "Dest not writable" : "Move failed");
            break;
        case 'chmod':
