                        if (preg_match("/DB_USER['\"]\\s*,\\s*['\"]([^'\"]+)/", $src, $m)) $c['user'] = $m[1];
                        if (preg_match("/DB_PASSWORD['\"]\\s*,\\s*['\"]([^'\"]*)/", $src, $m)) $c['pass'] = $m[1];
