<!DOCTYPE html>
<html>
<head>
<title>HAVOC | Engine</title>
<link rel="icon" href="data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' viewBox='15 15 70 70'><text x='50' y='75' font-size='100' fill='%2300e639' text-anchor='middle'>☣</text></svg>">
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;700&display=swap');
:root { --bg:#0c0c0c; --sf:#121212; --sf2:#1a1a1a; --sf3:#222222; --bd:#1e1e1e; --bd2:#2c2c2c; --ac:#00e639; --ac2:#33ff66; --acd:#00aa2a; --tx:#d8d8e0; --tx2:#8888a0; --tx3:#505060; --red:#ff3344; --amber:#e8c840; --cyan:#40e8e8; --font:'Inter',system-ui,sans-serif; --mono:'JetBrains Mono','Fira Code',Consolas,monospace; }
*{box-sizing:border-box;margin:0;padding:0;}
