::selection{background:var(--ac);color:#000;}
.card{background:var(--sf);border:1px solid var(--bd);padding:0;border-radius:16px;box-shadow:0 20px 60px rgba(0,0,0,0.6);}
.header{border-radius:16px 16px 0 0;} .status-bar{border-radius:0 0 16px 16px;}
/* Header */
.header{display:flex;justify-content:space-between;align-items:flex-start;padding:13px 22px 16px;border-bottom:1px solid var(--bd);}
.brand{display:flex;align-items:center;gap:10px;}
