.term{margin:14px 22px 0;border:1px solid var(--bd);border-radius:12px;overflow:hidden;box-shadow:inset 0 2px 8px rgba(0,0,0,0.3);}
.term-bar{display:flex;align-items:center;justify-content:space-between;padding:8px 14px;background:var(--sf2);border-bottom:1px solid var(--bd);}
.term-prompt{font-size:11px;color:var(--ac);font-family:var(--mono);font-weight:500;}
.term-prompt .host{color:var(--tx2);}
