.wc-min{background:#1a1a1a;border:1.5px solid #444;color:transparent;} .wc-min:hover{background:#ffbd2e;border-color:#ffbd2e;}
.wc-max{background:#1a1a1a;border:1.5px solid #444;color:transparent;} .wc-max:hover{background:#28c840;border-color:#28c840;}
.wc-x{background:#1a1a1a;border:1.5px solid #444;color:transparent;} .wc-x:hover{background:#ff5f57;border-color:#ff5f57;}
.console{background:#080808;padding:16px;height:175px;overflow-y:auto;color:var(--ac);white-space:pre-wrap;font-family:var(--mono);font-size:12px;line-height:1.7;}
.console::-webkit-scrollbar{width:4px;} .console::-webkit-scrollbar-thumb{background:var(--bd);border-radius:4px;} .console::-webkit-scrollbar-thumb:hover{background:var(--bd2);}
